pub fn push(&mut self, val: LuaValue) {
    let top = self.top.0 as usize;
    if top < self.stack.len() {
        self.stack[top] = StackValue { val, tbc_delta: 0 };
    } else {
        self.stack.push(StackValue { val, tbc_delta: 0 });
    }
    self.top = StackIdx(self.top.0 + 1);
}

